module counter_12
(
    input rst_n,
    input clk,
    input valid_count,
    output reg [3:0] out
);
    localparam [3:0] STATE_INIT = 4'b0000;
    localparam [3:0] STATE_NEXT = 4'b0001;
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n)
            out <= 4'd0;
        else if (valid_count) begin
            if (out == 4'd11) out <= 4'd0;
            else              out <= out + 1;
        end
    end
endmodule
